package com.example.dp.经典线性DP;

import java.util.Arrays;

public class 最长公共子序列 {

    /**
     * 给定两个字符串 text1 和 text2，返回这两个字符串的最长 公共子序列 的长度。如果不存在 公共子序列 ，返回 0 。
     *
     * 一个字符串的 子序列 是指这样一个新的字符串：它是由原字符串在不改变字符的相对顺序的情况下删除某些字符（也可以不删除任何字符）后组成的新字符串。
     *
     * 例如，"ace" 是 "abcde" 的子序列，但 "aec" 不是 "abcde" 的子序列。 两个字符串的 公共子序列 是这两个字符串所共同拥有的子序列。
     */

    public static void main(String[] args) {
        int len = longestCommonSubsequence(
            "",
            "");
        System.out.println(len);
    }

    private static char[] t1, t2;
    private static int[][] memo;

    public static int longestCommonSubsequence(String text1, String text2) {

        t1 = text1.toCharArray();
        t2 = text2.toCharArray();
        int n = t1.length;
        int m = t2.length;
        memo = new int[n][m];
        for(int[] arr : memo){
            Arrays.fill(arr,-1);
        }
        return dfs(n - 1, m - 1);
    }

    public static int dfs(int n, int m) {
        if (n < 0 || m < 0) {
            return 0;
        }

        if (memo[n][m] != -1) {
            return memo[n][m];
        }

        if (t1[n] == t2[m]) {
            return memo[n][m] = dfs(n - 1, m - 1) + 1;
        }

        return memo[n][m] = Math.max(dfs(n - 1, m), dfs(n, m - 1));
    }
}
